package ru.memearena.ranking.domain; public final class EloRatingCalculator { private static final int K=32; private EloRatingCalculator(){} public static Result calculate(int winner,int loser){ double ew=1.0/(1.0+Math.pow(10,(loser-winner)/400.0)); double el=1.0/(1.0+Math.pow(10,(winner-loser)/400.0)); return new Result((int)Math.round(winner+K*(1-ew)),(int)Math.round(loser+K*(0-el))); } public record Result(int winnerRatingAfter,int loserRatingAfter){} }
